# Three-tier sign-in risk policy set

# Tier 1: Block high sign-in risk
New-MgIdentityConditionalAccessPolicy -BodyParameter @{
    DisplayName = 'CA: Block High Sign-in Risk'
    State = 'enabled'
    Conditions = @{
        Users = @{ IncludeUsers = @('all') }
        Applications = @{ IncludeApplications = @('all') }
        SignInRiskLevels = @('high')
    }
    GrantControls = @{ Operator = 'OR'; BuiltInControls = @('block') }
}

# Tier 2: Require MFA for medium sign-in risk
New-MgIdentityConditionalAccessPolicy -BodyParameter @{
    DisplayName = 'CA: MFA for Medium Sign-in Risk'
    State = 'enabled'
    Conditions = @{
        Users = @{ IncludeUsers = @('all') }
        Applications = @{ IncludeApplications = @('all') }
        SignInRiskLevels = @('medium')
    }
    GrantControls = @{ Operator = 'OR'; BuiltInControls = @('mfa') }
}

# Tier 3: Allow low risk with no friction (explicit policy — optional)
# Low risk is typically allowed by default when no other policy matches
# Only add an explicit allow policy if you need to log or apply session controls

# Before enabling risk-based CA policies, run in Report-Only mode
# This lets you see WHAT WOULD HAPPEN without blocking anyone

# Create policy in reportOnly state
New-MgIdentityConditionalAccessPolicy -BodyParameter @{
    DisplayName = 'CA: Block High Sign-in Risk [REPORT-ONLY]'
    State = 'enabledForReportingButNotEnforcing'  # Report-Only
    Conditions = @{
        Users = @{ IncludeUsers = @('all') }
        Applications = @{ IncludeApplications = @('all') }
        SignInRiskLevels = @('high')
    }
    GrantControls = @{ Operator = 'OR'; BuiltInControls = @('block') }
}

# After 48-72h, query how many high-risk sign-ins occurred and what WOULD have been blocked
// KQL: Report-Only impact assessment
SigninLogs
| where TimeGenerated >= ago(7d)
| mv-expand ConditionalAccessPolicies
| where ConditionalAccessPolicies.displayName has 'REPORT-ONLY'
| extend WouldBlock = tostring(ConditionalAccessPolicies.result)
| summarize Count = count() by WouldBlock, UserPrincipalName
| order by Count desc
